      // v1.66 — typed model data binding ────────────────────────────────────────

      case View.ModelView(signal, bindingVar, template, _) =>
        val wrap      = freshVar()
        val rebuildFn = s"__modelview_${signal.id}"
        val sigJs     = jsString(signal.id)
        val urlJs     = jsString(signal.fetchUrl)
        val headersJs = signal.headersId.map(h => s", headers: JSON.parse(__ssc_signals[${jsString(h)}].value || '{}')").getOrElse("")
        // Register fetch signal state in reactiveSignals
        signal match
          case fjs: FetchJsonSignal =>
            reactiveSignals.update(fjs.id, "null")
            reactiveSignals.update(s"${fjs.id}_loading", "false")
            reactiveSignals.update(s"${fjs.id}_loaded", "false")
            reactiveSignals.update(s"${fjs.id}_error", "''")
          case _ =>
            reactiveSignals.update(signal.id, "''")
        // Ensure tick signal is registered so its cell exists
        if !reactiveSignals.contains(signal.tickId) then reactiveSignals.update(signal.tickId, "0")
        statements += s"const $wrap = document.createElement('span'); $wrap.style.display = 'contents';"
        // Capture template compilation; bindingVar becomes a parameter of the rebuild fn
        val (innerVar, body) = captureStatements(compile(template))
        statements += s"function $rebuildFn($bindingVar) {"
        statements += s"  while ($wrap.firstChild) $wrap.removeChild($wrap.firstChild);"
        body.foreach(stmt => statements += s"  $stmt")
        if innerVar != null then statements += s"  $wrap.appendChild($innerVar);"
        statements += s"}"
        statements += s"__ssc_signals[$sigJs].subs.add((data) => { if (data) $rebuildFn(data); });"
        val tickJs = jsString(signal.tickId)
        signal match
          case fjs: FetchJsonSignal =>
            val loadedJs  = jsString(s"${fjs.id}_loaded")
            val loadingJs = jsString(s"${fjs.id}_loading")
            val errorJs   = jsString(s"${fjs.id}_error")
            statements += s"__setSignal($loadingJs, true); fetch($urlJs$headersJs).then(r => r.json()).then(data => { __setSignal($sigJs, data); __setSignal($loadedJs, true); __setSignal($loadingJs, false); }).catch(e => { __setSignal($errorJs, String(e)); __setSignal($loadingJs, false); });"
            statements += s"__ssc_signals[$tickJs].subs.add((t) => { if (t > 0) fetch($urlJs$headersJs).then(r => r.json()).then(data => __setSignal($sigJs, data)); });"
          case _ =>
            statements += s"fetch($urlJs$headersJs).then(r => r.text()).then(data => __setSignal($sigJs, data));"
            statements += s"__ssc_signals[$tickJs].subs.add((t) => { if (t > 0) fetch($urlJs$headersJs).then(r => r.text()).then(data => __setSignal($sigJs, data)); });"
        wrap

      case View.ForModel(bindingVar, fieldPath, itemVar, template, _) =>
        val forWrap    = freshVar()
        val renderFn   = s"__formodel_${forWrap}"
        val prevItemVar = currentItemVar
        currentItemVar  = itemVar
        statements += s"const $forWrap = document.createElement('span'); $forWrap.style.display = 'contents';"
        val (innerVar, body) = captureStatements(compile(template))
        currentItemVar = prevItemVar
        val listExpr = if fieldPath.isEmpty then bindingVar else s"$bindingVar.$fieldPath"
        statements += s"function $renderFn($itemVar) {"
        body.foreach(stmt => statements += s"  $stmt")
        if innerVar != null then statements += s"  return $innerVar;"
        else statements += s"  return document.createTextNode('');"
        statements += s"}"
        statements += s"for (const $itemVar of ($listExpr || [])) { $forWrap.appendChild($renderFn($itemVar)); }"
        forWrap

      case View.ModelText(varName, fieldPath, _) =>
        val v = freshVar()
        statements += s"const $v = document.createTextNode(String($varName.$fieldPath));"
        v

    /** Empty-branch placeholder for ShowSignal — an empty text
     *  node so `replaceChild` always has a real Node to swap.
     *  Phase A2d: a hidden no-op. */
    private def placeholderNode(): String =
      val v = freshVar()
      statements += s"const $v = document.createTextNode('');"
      v

    private def attrValueJs(av: AttrValue): Option[String] = av match
      case AttrValue.Str(value)        => Some(jsString(value))
      case AttrValue.Bool(_)           => None  // handled as property assignment before attrValueJs is called
      case AttrValue.Num(value)        => Some(formatNumber(value))
      case AttrValue.Dynamic(read)     => Some(jsString(String.valueOf(read()))) // snapshot
      case AttrValue.Reactive(_)       => None  // handled as reactive subscription before attrValueJs is called
      case AttrValue.Absent            => None
      case AttrValue.RefBinding(_)     => None  // ref binding is wired imperatively in the Element case; no setAttribute

    private def formatNumber(d: Double): String =
      if d == d.toLong.toDouble then d.toLong.toString else d.toString

    /** Compile a single event handler into an `addEventListener`
     *  call on `targetVar`.  Simple / WithEvent are JVM closures
     *  that we can't translate to JS without a richer IR — they
     *  emit a marker comment for now.  SetSignalLiteral and
     *  IncrementSignal are A2c additions that lower cleanly. */
    private def compileEventHandler(targetVar: String, eventName: String, handler: EventHandler): Unit =
      handler match
        case EventHandler.Simple(_) | EventHandler.WithEvent(_) =>
          statements +=
            s"// $targetVar: '$eventName' handler is a JVM closure — A2c can't translate;" +
            " richer IR coming later."
        case EventHandler.InputChange(signal) =>
          registerSignal(signal)
          val nameJs = jsString(signal.id)
          statements += s"$targetVar.addEventListener('input', (e) => __setSignal($nameJs, e.target.value));"
        case EventHandler.SetSignalLiteral(signal, value) =>
          registerSignal(signal)
          val nameJs  = jsString(signal.id)
          val valueJs = jsLiteral(value)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignal($nameJs, $valueJs));"
        case EventHandler.IncrementSignal(signal, by) =>
          registerSignal(signal)
          val nameJs = jsString(signal.id)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignal($nameJs, __ssc_signals[$nameJs].value + $by));"
        case EventHandler.ToggleSignal(signal) =>
          registerSignal(signal)
          val nameJs = jsString(signal.id)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignal($nameJs, !__ssc_signals[$nameJs].value));"
        case EventHandler.PushSignalLiteral(list, value) =>
          registerList(list)
          val nameJs  = jsString(list.id)
          val valueJs = jsLiteral(value)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignalList($nameJs, __ssc_lists[$nameJs].value.concat([$valueJs])));"
        case EventHandler.ClearSignalList(list) =>
          registerList(list)
          val nameJs = jsString(list.id)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignalList($nameJs, []));"
        case EventHandler.FetchAction(method, url, body, tick, clearBody, hOpt) =>
          registerSignal(body)
          registerSignal(tick)
          hOpt.foreach(registerSignal)
          val bodyJs    = jsString(body.id)
          val tickJs    = jsString(tick.id)
          val urlJs     = jsString(url)
          val methodJs  = jsString(method)
          val clearJs   = if clearBody then s" __setSignal($bodyJs, '');" else ""
          val headersJs = hOpt.map(h => s", headers: JSON.parse(__ssc_signals[${jsString(h.id)}].value || '{}')").getOrElse("")
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
            s"fetch($urlJs, {method: $methodJs, body: __ssc_signals[$bodyJs].value$headersJs})" +
            s".then(r => r.text()).then(_ => { __setSignal($tickJs, __ssc_signals[$tickJs].value + 1);$clearJs }));"
        case EventHandler.RemoveSelfFromList(list) =>
          // A2e.2 — only meaningful inside an item template; outside,
          // emit an inert listener (graceful no-op).
          if inItemTemplate && currentItemList.exists(_.id == list.id) then
            registerList(list)
            val nameJs = jsString(list.id)
            // Capture __idx in the per-item closure so each instance
            // knows its own position; on click we filter that index out.
            statements += s"$targetVar.addEventListener(${jsString(eventName)}, ((__capturedIdx) => () => " +
                          s"__setSignalList($nameJs, __ssc_lists[$nameJs].value.filter((_, i) => i !== __capturedIdx)))(__idx));"
          else
            statements +=
              s"// $targetVar: '$eventName' is RemoveSelfFromList used outside an item template — no-op."
        case EventHandler.DeleteItem(idField, deleteUrl, tick, hOpt) =>
          if currentItemVar.nonEmpty then
            val tickJs    = jsString(tick.id)
            val delUrlJs  = jsString(deleteUrl)
            val headersJs = hOpt.map(h => s", headers: JSON.parse(__ssc_signals[${jsString(h.id)}].value || '{}')").getOrElse("")
            statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
              s"fetch($delUrlJs, {method: 'POST', body: String($currentItemVar.$idField)$headersJs})" +
              s".then(r => r.text()).then(_ => { __setSignal($tickJs, __ssc_signals[$tickJs].value + 1); }));"
          else
            statements +=
              s"// $targetVar: '$eventName' is DeleteItem outside ForModel context — no-op."

  /** A2e — JS array literal for a `ReactiveSignalList`'s initial
   *  value.  Each element goes through `jsLiteral` (same primitive
   *  type restriction as scalar signals). */
  private def jsArrayLiteral(items: Seq[Any]): String =
    items.map(jsLiteral).mkString("[", ", ", "]")

  /** JS literal for a signal value or SetSignalLiteral payload.
   *  Dispatches on runtime class because the trait surface is
   *  type-erased at the IR boundary. */
  private def jsLiteral(value: Any): String = value match
    case s: String     => jsString(s)
    case i: Int        => i.toString
    case l: Long       => l.toString
    case d: Double     => if d == d.toLong.toDouble then d.toLong.toString else d.toString
    case f: Float      => f.toDouble.toString
    case b: Boolean    => b.toString
    case null          => "null"
    case other         => throw new IllegalArgumentException(
      s"jsLiteral: unsupported value type ${other.getClass.getName} ($other).  " +
      "Supported: String / Int / Long / Double / Float / Boolean / null."
    )

  /** JS-encoded string literal — escapes the four characters
   *  (`\\`, `'`, newline, CR) that can break a single-quoted JS
   *  literal.  Other Unicode is passed through unchanged; the
   *  generated bundle is UTF-8 anyway. */
  private def jsString(s: String): String =
    val sb = new StringBuilder
    sb += '\''
    s.foreach {
      case '\\' => sb ++= "\\\\"
      case '\'' => sb ++= "\\'"
      case '\n' => sb ++= "\\n"
      case '\r' => sb ++= "\\r"
      case '<'  => sb ++= "\\u003c"  // belt-and-suspenders for inline scripts
      case c    => sb += c
    }
    sb += '\''
    sb.toString
